import React from "react";
import { useDispatch } from "react-redux";
import { updateQuantity } from "../../../app/cartSlice";
import styles from "./quantity.module.css";

interface QuantityProps {
  itemId: number;
  quantity: number;
  onQuantityChange: (newQuantity: number) => void; // Callback for quantity change
}

const Quantity: React.FC<QuantityProps> = ({ itemId, quantity, onQuantityChange }) => {
  const dispatch = useDispatch();

  const handleIncrement = () => {
    const newQuantity = quantity + 1;
    onQuantityChange(newQuantity); // Call the callback to update local quantity
    dispatch(updateQuantity({ id: itemId, quantity: newQuantity }));
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      const newQuantity = quantity - 1;
      onQuantityChange(newQuantity); // Call the callback to update local quantity
      dispatch(updateQuantity({ id: itemId, quantity: newQuantity }));
    }
  };

  return (
    <div className={styles.wrapper_buttons}>
      <button className={styles.btn_quanity} onClick={handleDecrement}> - </button>
      <span className={styles.count_quantity}>{quantity}</span>
      <button className={styles.btn_quanity} onClick={handleIncrement}> + </button>
    </div>
  );
};

export default Quantity;





